    //[TestCase("9", TestName = "DecodeDataMessage_RealWorldSfx9_MessageDecoded")]
    public void DecodeDataMessage_SfxRealWorld_MessageDecoded(string number)
    {
        // Arrange 
        var data = new List<byte> { 0x73 };

        var config = new byte[254];
        config[252] = 0xc;
        config[253] = 0xf;

        var msg = ResourceHelper.GetByteResource($"Bodoconsult.NetworkCommunication.Tests.Resources.sfx{number}RealWorld.bin");

        //var msgIdBytes = msg.AsMemory().Slice(0, 8).ToArray();

        //var msgId = BitConverter.ToUInt64(msgIdBytes);
        //var msgId1 = BitHelper.ToUInt64FromBigEndian(msgIdBytes);

        data.AddRange(msg.AsMemory(8).Span);

        var codec = new SfxpDataBlockCodec();
        codec.LoadStreamingConfig(config);

        // Act  
        var result = codec.DecodeDataBlock(data.ToArray());

        // Assert
        using (Assert.EnterMultipleScope())
        {
            Assert.That(result, Is.Not.Null);

            var db = (SfxpInboundDatablock)result;

            Assert.That(db, Is.Not.Null);
            ArgumentNullException.ThrowIfNull(db);

            Assert.That(db.Data.Length, Is.EqualTo(data.Count - 1));

            Assert.That(db.DataChunks.Count, Is.Not.Zero);
            Assert.That(db.DataChunks.Any(x => x.Channel == 0), Is.True);
            Assert.That(db.DataChunks.Any(x => x is { Channel: 0xc }), Is.True);
            Assert.That(db.DataChunks.Any(x => x.Channel == 255), Is.False);

            // Return chunks to pool
            foreach (var chunk in db.DataChunks)
            {
                chunk.ReturnDataChunkDelegate?.Invoke(chunk);
            }
            db.DataChunks.Clear();
        }
    }

